B.aaN=new A.o(B.h,["My engine temperature indicator is in the red. What should I do?","\u092e\u0947\u0930\u093e \u0907\u0902\u091c\u0928 \u0924\u093e\u092a\u092e\u093e\u0928 \u0938\u0902\u0915\u0947\u0924\u0915 \u0932\u093e\u0932 \u0930\u0902\u0917 \u092e\u0947\u0902 \u0939\u0948\u0964 \u092e\u0941\u091d\u0947 \u0915\u094d\u092f\u093e \u0915\u0930\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","\u0c28\u0c3e \u0c07\u0c02\u0c1c\u0c3f\u0c28\u0c4d \u0c09\u0c37\u0c4d\u0c23\u0c4b\u0c17\u0c4d\u0c30\u0c24 \u0c07\u0c02\u0c21\u0c3f\u0c15\u0c47\u0c1f\u0c30\u0c4d \u0c30\u0c46\u0c21\u0c4d \u0c32\u0c4b \u0c09\u0c02\u0c26\u0c3f. \u0c28\u0c47\u0c28\u0c41 \u0c0f\u0c2e\u0c3f \u0c1a\u0c47\u0c2f\u0c3e\u0c32\u0c3f?","\u0b8e\u0ba9\u0ba4\u0bc1 \u0b8e\u0b9e\u0bcd\u0b9a\u0bbf\u0ba9\u0bcd \u0bb5\u0bc6\u0baa\u0bcd\u0baa\u0ba8\u0bbf\u0bb2\u0bc8 \u0b95\u0bbe\u0b9f\u0bcd\u0b9f\u0bbf \u0b9a\u0bbf\u0bb5\u0baa\u0bcd\u0baa\u0bc1 \u0ba8\u0bbf\u0bb1\u0ba4\u0bcd\u0ba4\u0bbf\u0bb2\u0bcd \u0b89\u0bb3\u0bcd\u0bb3\u0ba4\u0bc1. \u0ba8\u0bbe\u0ba9\u0bcd \u0b8e\u0ba9\u0bcd\u0ba9 \u0b9a\u0bc6\u0baf\u0bcd\u0baf \u0bb5\u0bc7\u0ba3\u0bcd\u0b9f\u0bc1\u0bae\u0bcd?"],t.w)
B.a89=new A.o(B.h,["My car battery is dead and I need a jump start.","\u092e\u0947\u0930\u0940 \u0915\u093e\u0930 \u0915\u0940 \u092c\u0948\u091f\u0930\u0940 \u0916\u0924\u094d\u092e \u0939\u094b \u0917\u0908 \u0939\u0948 \u0914\u0930 \u092e\u0941\u091d\u0947 \u091c\u0902\u092a \u0938\u094d\u091f\u093e\u0930\u094d\u091f \u0915\u0940 \u091c\u0930\u0942\u0930\u0924 \u0939\u0948\u0964","\u0c28\u0c3e \u0c15\u0c3e\u0c30\u0c4d \u0c2c\u0c4d\u0c2f\u0c3e\u0c1f\u0c30\u0c40 \u0c21\u0c46\u0c21\u0c4d \u0c05\u0c2f\u0c3f\u0c02\u0c26\u0c3f \u0c2e\u0c30\u0c3f\u0c2f\u0c41 \u0c28\u0c3e\u0c15\u0c41 \u0c1c\u0c02\u0c2a\u0c4d \u0c38\u0c4d\u0c1f\u0c3e\u0c30\u0c4d\u0c1f\u0c4d \u0c15\u0c3e\u0c35\u0c3e\u0c32\u0c3f.","\u0b8e\u0ba9\u0ba4\u0bc1 \u0b95\u0bbe\u0bb0\u0bcd \u0baa\u0bc7\u0b9f\u0bcd\u0b9f\u0bb0\u0bbf \u0b87\u0bb1\u0ba8\u0bcd\u0ba4\u0bc1\u0bb5\u0bbf\u0b9f\u0bcd\u0b9f\u0ba4\u0bc1, \u0b8e\u0ba9\u0b95\u0bcd\u0b95\u0bc1 \u0b9c\u0bae\u0bcd\u0baa\u0bcd \u0bb8\u0bcd\u0b9f\u0bbe\u0bb0\u0bcd\u0b9f\u0bcd \u0ba4\u0bc7\u0bb5\u0bc8."],t.w)
B.a9_=new A.o(B.h,["I have run out of fuel on the highway and need refuel assistance.","\u0939\u093e\u0907\u0935\u0947 \u092a\u0930 \u092e\u0947\u0930\u093e \u0908\u0902\u0927\u0928 \u0916\u0924\u094d\u092e \u0939\u094b \u0917\u092f\u093e \u0939\u0948 \u0914\u0930 \u092e\u0941\u091d\u0947 \u0908\u0902\u0927\u0928 \u092d\u0930\u0928\u0947 \u0915\u0940 \u0938\u0939\u093e\u092f\u0924\u093e \u091a\u093e\u0939\u093f\u090f\u0964","\u0c39\u0c48\u0c35\u0c47\u0c2a\u0c48 \u0c28\u0c3e\u0c15\u0c41 \u0c07\u0c02\u0c27\u0c28\u0c02 \u0c05\u0c2f\u0c3f\u0c2a\u0c4b\u0c2f\u0c3f\u0c02\u0c26\u0c3f \u0c2e\u0c30\u0c3f\u0c2f\u0c41 \u0c07\u0c02\u0c27\u0c28\u0c02 \u0c28\u0c3f\u0c02\u0c2a\u0c47 \u0c38\u0c39\u0c3e\u0c2f\u0c02 \u0c15\u0c3e\u0c35\u0c3e\u0c32\u0c3f\u0964","\u0ba8\u0bc6\u0b9f\u0bc1\u0b9e\u0bcd\u0b9a\u0bbe\u0bb2\u0bc8\u0baf\u0bbf\u0bb2\u0bcd \u0b8e\u0ba9\u0b95\u0bcd\u0b95\u0bc1 \u0b8e\u0bb0\u0bbf\u0baa\u0bca\u0bb0\u0bc1\u0bb3\u0bcd \u0ba4\u0bc0\u0bb0\u0bcd\u0ba8\u0bcd\u0ba4\u0bc1\u0bb5\u0bbf\u0b9f\u0bcd\u0b9f\u0ba4\u0bc1, \u0b8e\u0bb0\u0bbf\u0baa\u0bca\u0bb0\u0bc1\u0bb3\u0bcd \u0ba8\u0bbf\u0bb0\u0baa\u0bcd\u0baa \u0b89\u0ba4\u0bb5\u0bbf \u0ba4\u0bc7\u0bb5\u0bc8."],t.w)
